import java.util.*;
// Node definition for singly-linked list
class Node {
    int data;
    Node next;

    Node(int d) {
        data = d;
        next = null;
    }
}

class Solution {

    // Function to segregate even and odd nodes in a linked list
    public Node segregateEvenOdd(Node head) {

        // Edge case: If list is empty or has only one node
        if (head == null || head.next == null) return head;

        // Create pointers for the heads and tails of even and odd lists
        Node odd = head;
        Node even = head.next;
        Node evenHead = even;

        // Traverse the linked list
        while (even != null && even.next != null) {
            odd.next = even.next;
            odd = odd.next;
            even.next = odd.next;
            even = even.next;
        }

        // Combine even and odd lists
        odd.next = evenHead;

        return head;
    }
}

// Driver code
class Main {
    public static void main(String[] args) {
        Solution sol = new Solution();

        // Creating linked list: 1 -> 2 -> 3 -> 4
        Node head = new Node(1);
        head.next = new Node(2);
        head.next.next = new Node(3);
        head.next.next.next = new Node(4);
        head.next.next.next.next = null;

        // Call segregation function
        Node newHead = sol.segregateEvenOdd(head);

        // Print result
        while (newHead != null) {
            System.out.print(newHead.data + " ");
            newHead = newHead.next;
        }
    }
}

